    if let Some(v) = quality_score { __out.quality_score = v; }
    if let Some(v) = processing_warnings { __out.processing_warnings = v; }
    if let Some(v) = annotations { __out.annotations = v; }
    if let Some(v) = children { __out.children = v; }
    if let Some(v) = uris { __out.uris = v; }
    if let Some(v) = structured_output { __out.structured_output = v; }
