#[derive(Clone, Default, serde::Serialize, serde::Deserialize)]
pub struct OcrConfidence {
    /// Detection confidence: how confident the OCR engine is that text exists here.
    ///
    /// PaddleOCR provides this as `box_score`, Tesseract doesn't have a direct equivalent.
    /// Range: 0.0 to 1.0 (or None if not available).
    pub detection: Option<f64>,
    /// Recognition confidence: how confident about the text content.
    ///
    /// Range: 0.0 to 1.0.
    pub recognition: f64,
}

impl OcrConfidence {
    #[must_use]

    pub fn new(recognition: Option<f64>, detection: Option<f64>) -> Self {
        Self { detection: detection, recognition: recognition.unwrap_or_default() }
    }
}

#[extendr]
pub fn new_ocrconfidence(
    detection: Option<f64>,
    recognition: Option<f64>
) -> OcrConfidence {
    let mut __out = <OcrConfidence>::default();
    if let Some(v) = detection { __out.detection = v; }
    if let Some(v) = recognition { __out.recognition = v; }
    __out
}


