#[allow(clippy::missing_errors_doc)]
#[extendr]
pub async fn extract_bytes(content: Vec<u8>, mime_type: String, config: ExtractionConfig) -> Result<ExtractionResult> {
    let config_json = serde_json::to_string(&config).map_err(|e| e.to_string())?;
    let config_core: kreuzberg::ExtractionConfig = serde_json::from_str(&config_json).map_err(|e| e.to_string())?;
    let rt = tokio::runtime::Runtime::new()?;
        rt.block_on(async { kreuzberg::extract_bytes(&content, &mime_type, &config_core).await.map_err(|e| e.into()) })
}

#[allow(clippy::missing_errors_doc)]
#[extendr]
pub async fn extract_file(path: String, mime_type: Option<String>, config: Option<ExtractionConfig>) -> Result<ExtractionResult> {
    let config_core: kreuzberg::ExtractionConfig = config.map(|v| {
        let json = serde_json::to_string(&v).map_err(|e| e.to_string())?;
        serde_json::from_str::<kreuzberg::ExtractionConfig>(&json).map_err(|e| e.to_string())
    }).transpose()?    .unwrap_or_default();
    let rt = tokio::runtime::Runtime::new()?;
        rt.block_on(async { kreuzberg::extract_file(std::path::PathBuf::from(path), mime_type.as_deref(), &config_core).await.map_err(|e| e.into()) })
}

#[allow(clippy::missing_errors_doc)]
#[extendr]
pub fn extract_file_sync(path: String, mime_type: Option<String>, config: Option<ExtractionConfig>) -> Result<ExtractionResult> {
    let config_core: kreuzberg::ExtractionConfig = config.map(|v| {
        let json = serde_json::to_string(&v).map_err(|e| e.to_string())?;
        serde_json::from_str::<kreuzberg::ExtractionConfig>(&json).map_err(|e| e.to_string())
    }).transpose()?    .unwrap_or_default();
    kreuzberg::extract_file_sync(std::path::PathBuf::from(path), mime_type.as_deref(), &config_core).map(ExtractionResult::from).map_err(|e| e.to_string())
}

