#[extendr]
pub fn register_ocr_backend(r_backend: extendr_api::Robj) -> Result<(), String> {
    let required_methods = ["process_image", "supports_language", "backend_type"];
    for method in &required_methods {
        match r_backend.dollar(method) {
            Ok(v) if !v.is_null() && !v.is_na() => {},
            _ => return Err(format!("Backend missing required method: {}", method)),
        }
    }

    let wrapper = ROcrBackendBridge::new(r_backend)?;
    let arc: Arc<dyn kreuzberg::plugins::OcrBackend> = Arc::new(wrapper);

    let registry = kreuzberg::plugins::registry::get_ocr_backend_registry();
    let mut registry = registry.write().map_err(|e| {
        format!("Failed to acquire registry lock: {}", e)
    })?;
    registry.register(arc).map_err(|e| {
        format!("Failed to register backend: {}", e)
    })
}


